'use client';

import React, { useState } from 'react';
import {
  Box,
  Typography,
  Button,
  Stack,
  Alert,
} from '@mui/material';
import CloudUploadIcon from '@mui/icons-material/CloudUpload';

export default function UploadDropzone() {
  const [file, setFile] = useState<File | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
    }
  };

  return (
    <Box
      sx={{
        minHeight: '100vh',
        bgcolor: '#f4f6f9',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        p: 2,
      }}
    >
      <Stack spacing={2} alignItems="center" sx={{ width: '100%', maxWidth: 450 }}>
        {/* Dropzone Box */}
        <Box
          component="label"
          sx={{
            border: '2px dashed #ccc',
            borderRadius: '12px',
            p: 6,
            width: '100%',
            textAlign: 'center',
            bgcolor: '#fff',
            cursor: 'pointer',
            transition: '0.3s',
            '&:hover': { borderColor: '#6c63ff', bgcolor: '#fafafa' },
          }}
        >
          <CloudUploadIcon sx={{ fontSize: 40, color: '#666', mb: 1 }} />
          {file ? (
            <Typography variant="body1" fontWeight="bold">
              📎 {file.name}
            </Typography>
          ) : (
            <>
              <Typography variant="h6" fontWeight="bold">
                อัพโหลดไฟล์งานที่ต้องการพิมพ์
              </Typography>
              <Typography variant="body2" color="text.secondary">
                คลิกหรือลากไฟล์มาวางที่บริเวณนี้
              </Typography>
            </>
          )}
          <input type="file" hidden onChange={handleFileChange} />
        </Box>

        {/* File Restrictions Info */}
        <Alert
          severity="info"
          sx={{
            bgcolor: '#ffe9f0',
            color: '#d6336c',
            borderRadius: '8px',
            fontSize: '0.85rem',
          }}
        >
          รองรับไฟล์ PDF เท่านั้น, ขนาดไม่เกิน 500MB <br />
          กรุณาเช็คไฟล์ของท่านว่ามีความละเอียด 300 dpi หรือไม่
        </Alert>

        {/* Upload Button */}
        <Button
          variant="contained"
          disabled={!file}
          sx={{
            width: '100%',
            borderRadius: '10px',
            fontWeight: 'bold',
            py: 1.5,
            background: 'linear-gradient(135deg,#6c63ff,#4e54c8)',
          }}
        >
          UPLOAD
        </Button>
      </Stack>
    </Box>
  );
}
